<template>
  <section class="console delivery-console">
    <header class="topbar"><RouterLink class="brand" to="/dashboard"><span class="brand-mark"><el-icon><Cpu /></el-icon></span><span>Wanxiang Agent</span></RouterLink><nav class="nav" aria-label="主导航"><RouterLink to="/dashboard">调度台</RouterLink><RouterLink to="/mrs">MR</RouterLink><RouterLink to="/issues">Issue</RouterLink></nav></header>
    <main class="main">
      <div class="page-head"><div><p class="eyebrow">DELIVERY CONTROL</p><h1>交付验收</h1><p>按不可变版本核对提交、Agent、测试与风险，再决定验收或进入下一轮返工。</p></div><el-button plain :loading="loading" @click="load">刷新</el-button></div>
      <div class="summary-strip"><div><strong>{{items.length}}</strong><span>交付版本</span></div><div><strong>{{awaiting}}</strong><span>待验收</span></div><div><strong>{{accepted}}</strong><span>已验收</span></div></div>
      <el-alert v-if="error" type="error" :closable="false" title="加载失败" :description="error" />
      <section class="delivery-layout" aria-live="polite" :aria-busy="loading">
        <aside class="queue panel"><div class="section-title"><h2>版本队列</h2><span>{{items.length}} 条</span></div><div v-if="!loading&&!items.length" class="empty-state"><strong>暂无交付快照</strong><span>项目负责人完成全部合并后，manager 会在这里生成验收版本。</span></div><button v-for="item in items" :key="item.id" class="version-card" :class="{active:selected?.snapshot.id===item.id}" @click="select(item.id)"><span><b class="mono">V{{item.version}}</b><i :data-status="item.status">{{label(item.status)}}</i></span><strong>任务 #{{item.task_id}}</strong><small class="mono">{{short(item.main_commit)}}</small><p>{{item.summary}}</p></button></aside>
        <article v-if="selected" class="panel evidence">
          <header class="evidence-head"><div><span class="mono muted">TASK-{{selected.snapshot.task_id}} / DELIVERY-V{{selected.snapshot.version}}</span><h2>{{selected.snapshot.summary}}</h2></div><span class="commit-seal mono">{{short(selected.snapshot.main_commit)}}</span></header>
          <section class="evidence-section"><h3><b>01</b>工作包与 Agent</h3><div class="proof-grid"><div v-for="mr in selected.snapshot.evidence.merge_requests" :key="mr.id"><span class="mono">MR-{{mr.id}} · STEP-{{mr.step_id}}</span><strong>{{mr.agent_name}}</strong><small>{{short(mr.source_commit)}} → {{short(mr.merge_commit)}}</small></div></div></section>
          <section class="evidence-section"><h3><b>02</b>测试证据</h3><div class="test-rail"><div v-for="test in selected.snapshot.evidence.tests" :key="test.command"><span>{{test.status}}</span><code>{{test.command}}</code><small>{{test.summary}}</small></div><p v-if="!selected.snapshot.evidence.tests.length" class="muted">没有登记测试证据。</p></div></section>
          <section class="evidence-section"><h3><b>03</b>风险与未完成项</h3><el-alert v-if="selected.snapshot.evidence.risks.length" type="warning" :closable="false" title="高风险操作需要单独确认" description="验收只确认代码交付，不会授权部署、删除、迁移、权限扩大或密钥操作。"/><div class="risk-grid"><div><strong>风险</strong><p v-for="risk in selected.snapshot.evidence.risks" :key="risk">{{risk}}</p><p v-if="!selected.snapshot.evidence.risks.length" class="muted">无已知风险</p></div><div><strong>未完成</strong><p v-for="entry in selected.snapshot.evidence.incomplete" :key="entry">{{entry}}</p><p v-if="!selected.snapshot.evidence.incomplete.length" class="muted">无未完成项</p></div></div></section>
          <section class="evidence-section history"><h3><b>04</b>决定历史与返工版本</h3><div class="timeline"><div v-for="decision in selected.decisions" :key="decision.id"><span></span><p><strong>{{label(decision.decision)}}</strong> · {{decision.created_by}}<small>{{decision.comment||'未附加意见'}}</small></p></div><div v-for="round in selected.rework_rounds" :key="`r${round.id}`"><span></span><p><strong>返工版本 P{{round.plan_version}}</strong> · {{label(round.status)}}<small>{{round.reason}}</small></p></div><p v-if="!selected.decisions.length&&!selected.rework_rounds.length" class="muted">尚无决定历史。</p></div></section>
          <section v-if="selected.snapshot.status==='awaiting_acceptance'" class="decision-box"><h3>提交决定</h3><el-input v-model="comment" type="textarea" :rows="3" maxlength="16384" show-word-limit placeholder="验收意见可选；拒绝或调整必须说明下一步"/><p v-if="validation" class="validation">{{validation}}</p><div><el-button type="success" :loading="submitting" @click="submitDecision('accepted')">验收</el-button><el-button type="danger" plain :loading="submitting" @click="submitDecision('rejected')">拒绝</el-button><el-button type="warning" plain :loading="submitting" @click="submitDecision('revision_requested')">要求调整</el-button></div></section>
        </article>
      </section>
    </main>
  </section>
</template>
<script setup lang="ts">
import {computed,onMounted,ref} from 'vue';import {RouterLink} from 'vue-router';import {Cpu} from '@element-plus/icons-vue';import {ElMessage} from 'element-plus';import {decideDelivery,getDelivery,listDeliveries,type DeliveryDetail,type DeliverySnapshot} from '../api/client'
const items=ref<DeliverySnapshot[]>([]),selected=ref<DeliveryDetail|null>(null),loading=ref(false),submitting=ref(false),comment=ref(''),error=ref(''),validation=ref(''),decisionKey=ref('');const awaiting=computed(()=>items.value.filter(x=>x.status==='awaiting_acceptance').length),accepted=computed(()=>items.value.filter(x=>x.status==='accepted').length);const labels:Record<string,string>={awaiting_acceptance:'待验收',accepted:'已验收',rejected:'已拒绝',revision_requested:'要求调整',planning:'规划中',planned:'已规划','blocked: missing_config':'缺少配置'};const label=(x:string)=>labels[x]||x;const short=(x:string)=>x?x.slice(0,10):'—'
async function load(){loading.value=true;error.value='';try{items.value=await listDeliveries();if(items.value.length)await select(selected.value?.snapshot.id||items.value[0].id);else selected.value=null}catch(e){error.value=e instanceof Error?e.message:'无法读取交付'}finally{loading.value=false}}
async function select(id:number){try{selected.value=await getDelivery(id);comment.value='';validation.value='';decisionKey.value=crypto.randomUUID()}catch(e){error.value=e instanceof Error?e.message:'无法读取交付详情'}}
async function submitDecision(decision:'accepted'|'rejected'|'revision_requested'){if(!selected.value||submitting.value)return;if(decision!=='accepted'&&!comment.value.trim()){validation.value='拒绝或要求调整时必须填写意见';return}validation.value='';submitting.value=true;try{await decideDelivery(selected.value.snapshot.id,{decision,comment:comment.value.trim(),idempotency_key:`delivery-${selected.value.snapshot.id}-${decision}-${decisionKey.value}`});ElMessage.success('决定已保存');decisionKey.value='';await load()}catch(e){error.value=e instanceof Error?e.message:'提交失败'}finally{submitting.value=false}}
onMounted(load)
</script>
<style scoped>
.delivery-console{--rail:#9a5d13;--soft:#fff4df}.eyebrow{margin:0 0 7px!important;color:var(--rail)!important;font:700 11px/1.2 Consolas,monospace;letter-spacing:.16em}.summary-strip{display:grid;grid-template-columns:repeat(3,1fr);margin-bottom:16px;border:1px solid var(--wx-line);background:#fff}.summary-strip div{display:flex;gap:10px;align-items:baseline;padding:14px 18px;border-right:1px solid var(--wx-line)}.summary-strip strong{font-size:23px}.summary-strip span,.section-title span{color:var(--wx-muted);font-size:12px}.delivery-layout{display:grid;grid-template-columns:minmax(280px,360px) minmax(0,1fr);gap:16px;align-items:start}.queue{padding:0;overflow:hidden;position:sticky;top:82px}.section-title{display:flex;justify-content:space-between;align-items:center;padding:16px 18px;border-bottom:1px solid var(--wx-line)}.section-title h2{margin:0}.version-card{display:grid;gap:7px;width:100%;padding:16px 18px;text-align:left;border:0;border-bottom:1px solid var(--wx-line);background:#fff;cursor:pointer}.version-card:hover,.version-card:focus-visible,.version-card.active{outline:none;background:var(--soft);box-shadow:inset 4px 0 var(--rail)}.version-card span,.evidence-head{display:flex;justify-content:space-between;gap:12px}.version-card i{padding:4px 8px;border-radius:999px;background:#eef1ee;font-style:normal;font-size:11px}.version-card i[data-status=accepted]{background:#dff0e8;color:#256957}.version-card p{margin:0;color:var(--wx-muted);font-size:12px;line-height:1.5}.evidence{padding:24px}.evidence-head{padding-bottom:18px;border-bottom:1px solid var(--wx-line)}.evidence-head h2{margin:6px 0 0;font-size:20px}.commit-seal{height:fit-content;padding:8px 10px;border:1px solid var(--rail);color:var(--rail)}.evidence-section{padding:20px 0;border-bottom:1px solid var(--wx-line)}.evidence-section h3{display:flex;gap:10px;margin:0 0 14px;font-size:15px}.evidence-section h3 b{color:var(--rail);font:700 11px Consolas,monospace}.proof-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px}.proof-grid>div{display:grid;gap:5px;padding:12px;border:1px solid var(--wx-line);background:#fbfcfa}.proof-grid small,.timeline small{display:block;color:var(--wx-muted)}.test-rail{display:grid;gap:8px}.test-rail>div{display:grid;grid-template-columns:auto 1fr;gap:8px;padding:11px 12px;border-radius:6px;background:#18221f;color:#eef8f3}.test-rail span{color:#72d4ae;font-size:11px}.test-rail small{grid-column:2;color:#b9c8c1}.risk-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:12px}.risk-grid>div{padding:13px;border:1px solid var(--wx-line)}.timeline>div{display:grid;grid-template-columns:14px 1fr;gap:8px}.timeline>div>span{width:8px;height:8px;margin-top:7px;border-radius:50%;background:var(--rail);box-shadow:0 0 0 4px var(--soft)}.timeline p{margin:0 0 13px}.decision-box{display:grid;gap:12px;padding-top:20px}.decision-box h3{margin:0}.validation{margin:0;color:var(--wx-red);font-size:13px}.empty-state{display:grid;place-items:center;gap:7px;min-height:180px;padding:24px;text-align:center;color:var(--wx-muted)}
@media (max-width: 900px) {.delivery-layout{grid-template-columns:1fr}.queue{position:static}.proof-grid,.risk-grid,.summary-strip{grid-template-columns:1fr}.summary-strip div{border-right:0;border-bottom:1px solid var(--wx-line)}}
@media (prefers-reduced-motion: reduce) {.version-card{transition:none}}
</style>
